solution: ```class Solution {
public:
    int numPairsDivisibleBy60(vector<int>& time) {
        int cnt[60] = {0};
        long long ans = 0;
        for (int t : time) {
            int r = t % 60;
            ans += cnt[(60 - r) % 60];
            cnt[r]++;
        }
        return (int)ans;
    }
};
```
